// Obyekt tiplərinin sintaksisi
interface User {
  name: string;
  age: number;
}

type Point = {
  x: number;
  y: number;
};

let user: User = { name: 'Ali', age: 25 };
let point: Point = { x: 10, y: 20 };
let anon: { id: number; title: string } = { id: 1, title: 'Test' };

console.log(user); // { name: 'Ali', age: 25 }
console.log(point); // { x: 10, y: 20 }
console.log(anon); // { id: 1, title: 'Test' }
// user.name = 42; // Xəta: number string-ə təyin edilə bilməz

// Readonly xüsusiyyətlər
interface Product {
  readonly id: number;
  name: string;
}

let product: Product = { id: 1, name: 'Telefon' };
console.log(product); // { id: 1, name: 'Telefon' }
// product.id = 2; // Xəta: readonly xüsusiyyət dəyişdirilə bilməz
product.name = 'Laptop'; // OK
console.log(product); // { id: 1, name: 'Laptop' }

// Opsional xüsusiyyətlər
interface Car {
  brand: string;
  model?: string;
}

let car1: Car = { brand: 'Toyota' };
let car2: Car = { brand: 'Honda', model: 'Civic' };

console.log(car1); // { brand: 'Toyota' }
console.log(car2); // { brand: 'Honda', model: 'Civic' }
// car1.brand = undefined; // Xəta: brand tələb olunur

// İndeks imza tipləri
interface Dictionary {
  [key: string]: number;
}

let scores: Dictionary = { math: 90, science: 85 };
console.log(scores); // { math: 90, science: 85 }
scores['history'] = 95;
console.log(scores); // { math: 90, science: 85, history: 95 }
// scores['art'] = 'A'; // Xəta: string number-ə təyin edilə bilməz

// İç-içə obyekt tipləri
interface Address {
  city: string;
  zip: number;
}

interface Person {
  name: string;
  address: Address;
}

let person: Person = {
  name: 'Vəli',
  address: { city: 'Bakı', zip: 1000 }
};

console.log(person); // { name: 'Vəli', address: { city: 'Bakı', zip: 1000 } }
// person.address.city = 42; // Xəta: number string-ə təyin edilə bilməz

// Obyekt vs tuple
let object: { name: string; age: number } = { name: 'Ali', age: 25 };
let tuple: [string, number] = ['Ali', 25];

console.log(object.name); // Ali
console.log(tuple[0]); // Ali

// Praktik nümunə
interface Product {
  id: number;
  name: string;
  price: number;
}

function displayProduct(product: Product): void {
  console.log(`Məhsul: ${product.name}, Qiymət: ${product.price}`);
}

let product: Product = { id: 1, name: 'Telefon', price: 500 };
displayProduct(product);
// Çıxış: Məhsul: Telefon, Qiymət: 500

// Təhlükəsizlik nümunəsi
interface User {
  name: string;
  age: number;
}

let user: User = { name: 'Vəli', age: 30 };
if (typeof user.name === 'string') {
  console.log(user.name.toUpperCase()); // VƏLİ
}
// user.age = 'otuz'; // Xəta: string number-ə təyin edilə bilməz

// Səhvə yol açan nümunə
let unsafe: any = { name: 'Ali', age: 25 };
unsafe.age = 'yirmi beş'; // Təhlükəsiz deyil, runtime səhvi ola bilər
console.log(unsafe); // { name: 'Ali', age: 'yirmi beş' }

// Düzgün yol
interface User {
  name: string;
  age: number;
}
let safe: User = { name: 'Ali', age: 25 };
console.log(safe); // { name: 'Ali', age: 25 }
// safe.age = 'yirmi beş'; // Xəta: string number-ə təyin edilə bilməz

// Real layihə ssenarisi
interface Product {
  id: number;
  name: string;
  price: number;
}

function filterExpensiveProducts(products: Product[], minPrice: number): Product[] {
  return products.filter(product => product.price > minPrice);
}

let products: Product[] = [
  { id: 1, name: 'Telefon', price: 500 },
  { id: 2, name: 'Laptop', price: 1000 },
  { id: 3, name: 'Planşet', price: 300 },
];

let expensive: Product[] = filterExpensiveProducts(products, 500);
console.log(expensive); // [{ id: 2, name: 'Laptop', price: 1000 }]

