// Object type syntax
interface User {
  name: string;
  age: number;
}

type Point = {
  x: number;
  y: number;
};

let user: User = { name: 'Alice', age: 25 };
let point: Point = { x: 10, y: 20 };
let anon: { id: number; title: string } = { id: 1, title: 'Test' };

console.log(user); // { name: 'Alice', age: 25 }
console.log(point); // { x: 10, y: 20 }
console.log(anon); // { id: 1, title: 'Test' }
// user.name = 42; // Error: number cannot be assigned to string

// Readonly properties
interface Product {
  readonly id: number;
  name: string;
}

let product: Product = { id: 1, name: 'Phone' };
console.log(product); // { id: 1, name: 'Phone' }
// product.id = 2; // Error: cannot modify readonly property
product.name = 'Laptop'; // OK
console.log(product); // { id: 1, name: 'Laptop' }

// Optional properties
interface Car {
  brand: string;
  model?: string;
}

let car1: Car = { brand: 'Toyota' };
let car2: Car = { brand: 'Honda', model: 'Civic' };

console.log(car1); // { brand: 'Toyota' }
console.log(car2); // { brand: 'Honda', model: 'Civic' }
// car1.brand = undefined; // Error: brand is required

// Index signatures
interface Dictionary {
  [key: string]: number;
}

let scores: Dictionary = { math: 90, science: 85 };
console.log(scores); // { math: 90, science: 85 }
scores['history'] = 95;
console.log(scores); // { math: 90, science: 85, history: 95 }
// scores['art'] = 'A'; // Error: string cannot be assigned to number

// Nested object types
interface Address {
  city: string;
  zip: number;
}

interface Person {
  name: string;
  address: Address;
}

let person: Person = {
  name: 'Bob',
  address: { city: 'Baku', zip: 1000 }
};

console.log(person); // { name: 'Bob', address: { city: 'Baku', zip: 1000 } }
// person.address.city = 42; // Error: number cannot be assigned to string

// Object vs tuple
let object: { name: string; age: number } = { name: 'Alice', age: 25 };
let tuple: [string, number] = ['Alice', 25];

console.log(object.name); // Alice
console.log(tuple[0]); // Alice

// Practical example
interface Product {
  id: number;
  name: string;
  price: number;
}

function displayProduct(product: Product): void {
  console.log(`Product: ${product.name}, Price: ${product.price}`);
}

let product: Product = { id: 1, name: 'Phone', price: 500 };
displayProduct(product);
// Output: Product: Phone, Price: 500

// Security example
interface User {
  name: string;
  age: number;
}

let user: User = { name: 'Bob', age: 30 };
if (typeof user.name === 'string') {
  console.log(user.name.toUpperCase()); // BOB
}
// user.age = 'thirty'; // Error: string cannot be assigned to number

// Error-prone example
let unsafe: any = { name: 'Alice', age: 25 };
unsafe.age = 'twenty-five'; // Unsafe, may cause runtime errors
console.log(unsafe); // { name: 'Alice', age: 'twenty-five' }

// Correct approach
interface User {
  name: string;
  age: number;
}
let safe: User = { name: 'Alice', age: 25 };
console.log(safe); // { name: 'Alice', age: 25 }
// safe.age = 'twenty-five'; // Error: string cannot be assigned to number

// Real-world scenario
interface Product {
  id: number;
  name: string;
  price: number;
}

function filterExpensiveProducts(products: Product[], minPrice: number): Product[] {
  return products.filter(product => product.price > minPrice);
}

let products: Product[] = [
  { id: 1, name: 'Phone', price: 500 },
  { id: 2, name: 'Laptop', price: 1000 },
  { id: 3, name: 'Tablet', price: 300 },
];

let expensive: Product[] = filterExpensiveProducts(products, 500);
console.log(expensive); // [{ id: 2, name: 'Laptop', price: 1000 }]

