  name: string;
  age: number;
}

type Point = {
  x: number;
  y: number;
};

let user: User = { name: 'Алиса', age: 25 };
let point: Point = { x: 10, y: 20 };
let anon: { id: number; title: string } = { id: 1, title: 'Тест' };

console.log(user); // { name: 'Алиса', age: 25 }
console.log(point); // { x: 10, y: 20 }
console.log(anon); // { id: 1, title: 'Тест' }
// user.name = 42; // Ошибка: number не может быть присвоен string

// Свойства только для чтения
interface Product {
  readonly id: number;
  name: string;
}

let product: Product = { id: 1, name: 'Телефон' };
console.log(product); // { id: 1, name: 'Телефон' }
// product.id = 2; // Ошибка: нельзя изменить свойство только для чтения
product.name = 'Ноутбук'; // OK
console.log(product); // { id: 1, name: 'Ноутбук' }

// Необязательные свойства
interface Car {
  brand: string;
  model?: string;
}

let car1: Car = { brand: 'Toyota' };
let car2: Car = { brand: 'Honda', model: 'Civic' };

console.log(car1); // { brand: 'Toyota' }
console.log(car2); // { brand: 'Honda', model: 'Civic' }
// car1.brand = undefined; // Ошибка: brand обязателен

// Индексные сигнатуры
interface Dictionary {
  [key: string]: number;
}

let scores: Dictionary = { math: 90, science: 85 };
console.log(scores); // { math: 90, science: 85 }
scores['history'] = 95;
console.log(scores); // { math: 90, science: 85, history: 95 }
// scores['art'] = 'A'; // Ошибка: string не может быть присвоен number

// Вложенные типы объектов
interface Address {
  city: string;
  zip: number;
}

interface Person {
  name: string;
  address: Address;
}

let person: Person = {
  name: 'Боб',
  address: { city: 'Баку', zip: 1000 }
};

console.log(person); // { name: 'Боб', address: { city: 'Баку', zip: 1000 } }
// person.address.city = 42; // Ошибка: number не может быть присвоен string

// Объект vs кортеж
let object: { name: string; age: number } = { name: 'Алиса', age: 25 };
let tuple: [string, number] = ['Алиса', 25];

console.log(object.name); // Алиса
console.log(tuple[0]); // Алиса

// Практический пример
interface Product {
  id: number;
  name: string;
  price: number;
}

function displayProduct(product: Product): void {
  console.log(`Продукт: ${product.name}, Цена: ${product.price}`);
}

let product: Product = { id: 1, name: 'Телефон', price: 500 };
displayProduct(product);
// Вывод: Продукт: Телефон, Цена: 500

// Пример безопасности
interface User {
  name: string;
  age: number;
}

let user: User = { name: 'Боб', age: 30 };
if (typeof user.name === 'string') {
  console.log(user.name.toUpperCase()); // БОБ
}
// user.age = 'тридцать'; // Ошибка: string не может быть присвоен number

